import { filtrarValoresUnicos } from './filtrarValoresUnicos';
import { achatar } from './achatar';

/**
 * Concatena qualquer número de valores booleanos, strings, números, datas ou vetores desses tipos.
 * Mantém apenas valorfes únicos.
 *
 * **Uso:**
 * ```
 * const novoVetor = concatenarValoresUnicos([1, 'a', 'b', 3], [2, 'a', 'b'], 3, 'c');
 * console.log(novoVetor);
 * // Saída: [1, 'a', 'b', 3, 2, 'c']
 * ```
 * @param args Qualquer número de vetores ou valores a serem concatenados
 */
export function concatenarValoresUnicos(...args: unknown[]): unknown[] {
  args = args.map((arg) => (Array.isArray(arg) ? achatar(arg) : arg));
  return Array.prototype.concat(...args).filter(filtrarValoresUnicos);
}
