import type { TCelula, TTabela } from '../predicados';
import { tipoTabela } from '../predicados';

/**
 * Transpõe uma tabela ou lança um erro se o valor de entrada não é uma tabela.
 *
 * @param tabela
 */
export function transpor(tabela: TTabela<TCelula>): TTabela<TCelula> {
  if (!tipoTabela(tabela)) throw new Error('A função aceita somente uma tabela!');
  return tabela[0].map((_col, indice) => tabela.map((linha) => linha[indice]));
}
