import { converterEmNumero } from './converterEmNumero';

/**
 * Formata um valor numérico como percentagem utilizando a classe nativa `Intl`.
 *
 * Uso:
 * ```
 * console.log(formatoPercentual(0.234567, 2, 'pt-BR'));
 * // Saída: 23,46%
 * ```
 * @param valor
 * @param precisao Número de casas decimais. Se omitido, serão zero casas decimais.
 * @param localidade Identificador de localidade Unicode BCP 47, como "pt-BR" ou "en-US". Se omitido, o valor "pt-BR" é utilizado.
 */
export function formatoPercentual(valor: number | string, precisao = 0, localidade = 'pt-BR'): string {
  const opcoes = { style: 'percent', maximumFractionDigits: precisao };
  return new Intl.NumberFormat(localidade, opcoes).format(converterEmNumero(valor));
}
