import { intervalo } from './intervalo';

export type TValorPreenchimento = string | number | boolean | Date | null | undefined;

/**
 * Similar à função `zip` do Python.
 *
 * **Uso:**
 * ```
 * const novoVetor = zip([1, 2, 3], ['a', 'b', 'c'], [true, false, true]);
 * console.log(novoVetor);
 * // Saída: [[1, 'a', true], [2, 'b', false], [3, 'c', true]]
 * ```
 * @param vetor
 * @param preencherCom
 */
export function combinar(
  vetor: TValorPreenchimento[][],
  preencherCom: TValorPreenchimento = ''
): TValorPreenchimento[][] {
  const tamanhoColuna = vetor.reduce((max, linha) => Math.max(max, linha.length), 0);
  return intervalo(tamanhoColuna).map((_, col) => vetor.map((linha) => linha[col] ?? preencherCom));
}
