import type { TValor } from './tipoValor';
import { tipoData } from './tipoData';

export type TCelula = TValor | null | undefined;
export type TTabela<T extends TCelula> = T[][];

/**
 * Predicate that asserts if an array is a table of primitive values.
 * A table is an array of arrays of equal length. The inner arrays are rows and each position in a row corresponds to a column.
 * Values in a table are called cells. Cells may be read as follows: `table[row][column]`.
 *
 * @param o
 */
export function tipoTabela(o: unknown): o is TTabela<TCelula> {
  const tamanhoLinha = Array.isArray(o) && Array.isArray(o[0]) ? o[0].length : -1;
  const tipoPermitido = (valor: unknown) => {
    return (
      typeof valor === 'boolean' ||
      typeof valor === 'number' ||
      typeof valor === 'string' ||
      tipoData(valor) ||
      valor === null ||
      valor === undefined
    );
  };
  const linhaValida = (linha: unknown[]) =>
    Array.isArray(linha) && linha.length === tamanhoLinha && linha.every((cell) => tipoPermitido(cell));
  return Array.isArray(o) && o.length > 0 && o.every(linhaValida);
}
