import { tipoValor, tipoData } from '../predicados';

/**
 * Para uso como callback no método nativo `filter`.
 * Os parâmetros são aqueles passados pelo método nativo.
 *
 * @param valor
 * @param indice
 * @param vetor
 */
export function filtrarValoresUnicos<T>(valor: T, indice: number, vetor: T[]): boolean {
  if (!tipoValor(valor)) return false;
  if (tipoData(valor))
    return vetor.findIndex((data) => tipoData(data) && data.valueOf() === valor.valueOf()) === indice;
  return vetor.indexOf(valor) === indice;
}
