/**
 * Achata um vetor de qualquer profundidade, recursivamente.
 *
 * **Uso:**
 * ```
 * const novoVetor = achatar([1, ['a', 'b', [3], [[2, ['a']], 'b']]]);
 * console.log(novoVetor);
 * // Saída: [1, 'a', 'b', 3, 2, 'a', 'b']
 * ```
 * @param vetor O vetor a ser achatado
 */
export function achatar(vetor: unknown[]): unknown[] {
  let result = [] as unknown[];
  for (let i = 0; i < vetor.length; i++) {
    const talvez = vetor[i];
    if (Array.isArray(talvez)) {
      result = Array.prototype.concat(result, achatar(talvez));
    } else {
      result.push(talvez);
    }
  }
  return result;
}
