import type { TCelula, TTabela } from '../predicados';

/**
 * Concatenar duas tabelas, para a direita ou na sequencia, criando uma nova tabela.
 *
 * @param tabela_a
 * @param tabela_b
 * @param paraDireita
 * @param preencherCom
 * @returns A nova tabela.
 */
export function concatenarTabelas(
  tabela_a: TTabela<TCelula>,
  tabela_b: TTabela<TCelula>,
  paraDireita = false,
  preencherCom: TCelula = null
): TTabela<TCelula> {
  const maxLins = Math.max(tabela_a.length, tabela_b.length);
  const maxColsA = tabela_a.reduce((max, linha) => Math.max(max, linha.length), 0);
  const maxColsB = tabela_b.reduce((max, linha) => Math.max(max, linha.length), 0);

  const tabela: TTabela<TCelula> = [];
  if (paraDireita) {
    for (let i = 0; i < maxLins; i++) {
      const row_a = obterLinhaPreenchida(tabela_a[i], maxColsA, preencherCom);
      const row_b = obterLinhaPreenchida(tabela_b[i], maxColsB, preencherCom);
      tabela.push([...row_a, ...row_b]);
    }
  } else {
    const maxCols = Math.max(maxColsA, maxColsB);
    tabela_a.forEach((linha) => {
      tabela.push(obterLinhaPreenchida(linha, maxCols, preencherCom));
    });
    tabela_b.forEach((linha) => {
      tabela.push(obterLinhaPreenchida(linha, maxCols, preencherCom));
    });
  }

  return tabela;
}

function obterLinhaPreenchida(linha: TCelula[], tamanho: number, preencherCom: TCelula = null): TCelula[] {
  if (Array.isArray(linha)) {
    if (linha.length === tamanho) return linha;
    if (linha.length > tamanho) return linha.slice(0, tamanho);
    const preenchida = linha;
    while (preenchida.length < tamanho) {
      preenchida.push(preencherCom);
    }
    return preenchida;
  }
  return new Array(tamanho).fill(preencherCom);
}
