import { diferencaEntreDatas } from './diferencaEntreDatas';
import { primeiroDiaDoMes } from './primeiroDiaDoMes';
import { intervalo } from '../vetores';
import { TIPO_DURACAO } from '../enums';

/**
 * Retorna um vetor de datas representando a sequência de competências a partir do parâmetro `inicio` até o parâmetro `fim`.
 * Por convenção, cada competência corresponde ao primeiro dia do mês.
 *
 * Uso:
 * ```
 * console.log(intervaloCompetencia(new Date(2020, 0, 1), new Date(2020, 3, 1)));
 * // Saída: [Wed Jan 01 2020 00:00:00 GMT-0000 (UTC), Sat Feb 01 2020 00:00:00 GMT-0000 (UTC), Sun Mar 01 2020 00:00:00 GMT-0000 (UTC), Wed Apr 01 2020 00:00:00 GMT-0000 (UTC)]
 * ```
 *
 * @param inicio
 * @param fim
 */
export function intervaloCompetencias(inicio: Date, fim: Date): Date[] {
  const months = diferencaEntreDatas(inicio, fim, TIPO_DURACAO.MESES) + 1;
  return intervalo(months).map((monthsToAdd) => primeiroDiaDoMes(inicio, monthsToAdd));
}
