import { normalizar } from './normalizar';
import { semEspacos } from './semEspacos';

/**
 * Formata uma string no padrão `camelCase`.
 * Lança um erro se o parâmetro de entrada não é uma string (pelas outras funções invocadas).
 *
 * @param str
 */
export function formatoCamelCase(str: string): string {
  return semEspacos(
    normalizar(str).replace(/(?:^\w|[A-Z]|\b\w)/g, (word, index) =>
      index === 0 ? word.toLowerCase() : word.toUpperCase()
    )
  );
}
