import { validarData } from '../validacao';
import { FORMATO_DATA } from '../enums';

/**
 * Converte uma data válida em uma string.
 *
 * Uso:
 * ```
 * console.log(converterDataEmString(new Date('2020-01-01T00:00'), FORMATO_DATA.LOCALIDADE, 'pt-BR', 'America/Sao_Paulo')));
 * // Saída: 1º de janeiro de 2020
 * ```
 *
 * @param data Um objeto nativo do tipo `Date`
 * @param formato O formato de saída
 * @param localidade Identificador de localidade Unicode BCP 47, tal como "pt-BR" ou "en-US". Se omitido, o valor "pt-BR" é utilizado.
 * @param fuso Uma região de fuso-horário válida ou um registro válido da base de dados de fuso-horários da IANA, como "America/Sao_Paulo" ou "UTC". Se omitido, o valor "America/Sao_Paulo" é utilizado.
 */
export function converterDataEmString(
  data: Date,
  formato: FORMATO_DATA = FORMATO_DATA.ISO_ABREVIADO,
  localidade = 'pt-BR',
  fuso = 'America/Sao_Paulo'
): string {
  if (!validarData(data)) throw new Error('Data inválida!');
  switch (formato) {
    case FORMATO_DATA.ISO:
      return paraISO(data);
    case FORMATO_DATA.LOCALIDADE:
      return paraLocalidade(data, localidade, fuso);
    case FORMATO_DATA.ISO_ABREVIADO:
      return paraISOAbreviado(data);
    case FORMATO_DATA.LOCALIDADE_ABREVIADO:
      return paraLocalidadeAbreviado(data, localidade, fuso);
    default:
      throw new Error('Formato de saída inválido!');
  }
}

function paraISO(date: Date): string {
  return date.toISOString();
}

function paraISOAbreviado(date: Date): string {
  return date.toISOString().substring(0, 10);
}

function paraLocalidade(date: Date, locale: string, timezone: string): string {
  const resultado = date.toLocaleDateString(locale, {
    year: 'numeric',
    month: 'long',
    day: 'numeric',
    timeZone: timezone
  });
  return resultado.replace('1 ', '1º ');
}

function paraLocalidadeAbreviado(date: Date, locale: string, timezone: string): string {
  return date.toLocaleDateString(locale, { timeZone: timezone });
}
