import { clonar } from './clonar';
import { tipoObjeto } from '../predicados';

/**
 * Clona somente as propriedades fornecidas pelo objeto de referência. Útil quando se quer descartar dadso desnecessários ou não desejados.
 *
 * Uso:
 * ```
 * const alvo: any = { a: null, b: null, c: null };
 * const refs: any = [{ a: null }, { b: null }, { c: null }, { d: null }];
 * console.log(clonarParte(alvo, refs[0]));
 * // Saída: { a: null }
 * ```
 * @param alvo
 * @param ref
 */
export function clonarParte(alvo: Record<string, unknown>, ref: Record<string, unknown>): Record<string, unknown> {
  const keys = Object.keys(ref);
  return keys.reduce((r, k) => {
    if (Array.isArray(alvo[k]) || tipoObjeto(alvo[k])) {
      r[k] = clonar(alvo[k]);
      return r;
    }
    r[k] = alvo[k];
    return r;
  }, {} as Record<string, unknown>);
}
