import { tipoString } from '../predicados';

/**
 * Remove todos os acentos de uma string.
 * Lança um erro se o parâmetro de entrada não é uma string.
 *
 * @param str
 */
export function semAcentuacao(str: string): string {
  if (!tipoString(str)) throw new Error('A função aceita somente strings!');
  return str.normalize('NFD').replace(/[\u0300-\u036f]/g, '');
}
