import { converterEmNumero } from './converterEmNumero';
import { CODIGO_MOEDA } from '../enums';

/**
 * Formata um número como moeda, utilizando a classe nativa `Intl`.
 *
 * Uso:
 * ```
 * console.log(formatoMoeda('1000000,2345', CODIGO_MOEDA.BRL, 'pt-BR'));
 * // Output: R$ 1.000.00,23
 * ```
 * @param valor
 * @param moeda Qualquer dos códigos constantes da enumeração `CODIGO_MOEDA`. Se omitido, é utilizado o código BRL.
 * @param localidade Um identificador de localidade Unicode BCP 47, como "pt-BR" ou "en-US". Se omitido, a localidade "pt-BR" é utilizada.
 */
export function formatoMoeda(valor: number | string, moeda = CODIGO_MOEDA.BRL, localidade = 'pt-BR'): string {
  const number = converterEmNumero(valor);
  const opcoes = { style: 'currency', currency: moeda };
  return new Intl.NumberFormat(localidade, opcoes).format(number);
}
