import { mesmaData } from './mesmaData';
import { primeiroDiaDoMes } from './primeiroDiaDoMes';
import { ultimodiaDoMes } from './ultimodiaDoMes';
import { validarData, tabelaDeDatas } from '../validacao';
import type { TTabela } from '../predicados';

/**
 * Dada um tabela de competências (explicado abaixo), retorna o índice de uma data na referida tabela, ou seja, retorna o índice da linha em que o mês e o ano da data fornecida correspondem aos da competência naquela linha.
 * Uma tabela é um vetor de vetores de igual tamanho. Os vetores internos são linhas e cada item na linha corresponde a uma coluna.
 * Os valores em uma tabela são chamados de "células". Células podem ser acessadas como segue: `tabela[linha][coluna]`.
 * Um competência é uma data que, por convenção, representa um mês. A data que representa a competência corresponde sempre ao primeiro dia do mês.
 * Uma tabela de competências é uma tabela de coluna única, onde (i) cada linha corresponde a uma competência; (ii) as competências estão posicionadas em ordem crescente; e (iii) não há lacunas internas, ou seja, entre a competência inicial e final a tabela contém todas as competências intermediárias.
 *
 * Exemplo:
 * ```
 * const data = new Date(2021, 2, 20);
 * const tabela = [
 *   [new Date('2020-01-01T00:00')],
 *   [new Date('2020-02-01T00:00')],
 *   [new Date('2020-03-01T00:00')],
 *   [new Date('2020-04-01T00:00')],
 *   [new Date('2020-05-01T00:00')],
 *   [new Date('2020-06-01T00:00')],
 *   [new Date('2020-07-01T00:00')],
 *   [new Date('2020-08-01T00:00')],
 *   [new Date('2020-09-01T00:00')],
 *   [new Date('2020-10-01T00:00')],
 *   [new Date('2020-11-01T00:00')],
 *   [new Date('2020-12-01T00:00')],
 *   [new Date('2021-01-01T00:00')],
 *   [new Date('2021-02-01T00:00')],
 *   [new Date('2021-03-01T00:00')]
 * ];
 * console.log(posicaoNaTabeladeCompetencias(tabela, data));
 * // Saída: 14
 * ```
 *
 * @param tabela Uma tabela de competências
 * @param data Uma data qualquer
 */
export function posicaoNaTabelaDeCompetencias(tabela: TTabela<Date>, data: Date): number {
  if (!tabelaDeDatas(tabela)) throw new Error('Esta função aceita somente uma tabela de datas!');
  if (!validarData(data)) throw new Error('A competência deve ser uma data válida!');
  if (
    tabela[0][0].valueOf() > data.valueOf() ||
    ultimodiaDoMes(tabela[tabela.length - 1][0] as Date).valueOf() < data.valueOf()
  ) {
    throw new Error('Competência fora do intervalo!');
  }
  return tabela.reduce(
    (n, linha, indice) => (mesmaData(primeiroDiaDoMes(linha[0] as Date), primeiroDiaDoMes(data)) ? indice : n),
    0
  );
}
