/* eslint-disable no-console */
/* eslint-disable @typescript-eslint/no-explicit-any */

import { tipoBooleano } from '../predicados';

/* eslint-disable @typescript-eslint/no-unused-vars */
export class Depurador {
  static estilos = {
    azul: 'background-color: #2979FF; color: #ffffff; font-weight: bold; padding: 2px 6px;',
    vermelho: 'background-color: #F44336; color: #ffffff; font-weight: bold; padding: 2px 6px;',
    laranja: 'background-color: #F57F17; color: #ffffff; font-weight: bold; padding: 2px 6px;',
    verde: 'background-color: #2E7D32; color: #ffffff; font-weight: bold; padding: 2px 6px;',
    cinza: 'background-color: #757575; color: #ffffff; font-weight: bold; padding: 2px 6px;'
  };

  private modoDesenvolvimento = false;

  constructor(modoDesenvolvimento?: boolean) {
    if (tipoBooleano(modoDesenvolvimento)) {
      this.modoDesenvolvimento = modoDesenvolvimento;
    }
  }

  console = {
    assert: this.modoDesenvolvimento ? console.assert : (..._args: any[]) => void 0,
    count: this.modoDesenvolvimento ? console.count : (..._args: any[]) => void 0,
    debug: this.modoDesenvolvimento ? console.debug : (..._args: any[]) => void 0,
    // retirado, por conta de um warning no processo de build
    // dir: this.modoDesenvolvimento ? console.dir : (..._args: any[]) => void 0,
    error: this.modoDesenvolvimento ? console.error : (..._args: any[]) => void 0,
    group: this.modoDesenvolvimento ? console.group : (..._args: any[]) => void 0,
    groupCollapsed: this.modoDesenvolvimento ? console.groupCollapsed : (..._args: any[]) => void 0,
    groupEnd: this.modoDesenvolvimento ? console.groupEnd : (..._args: any[]) => void 0,
    info: this.modoDesenvolvimento ? console.info : (..._args: any[]) => void 0,
    log: this.modoDesenvolvimento ? console.log : (..._args: any[]) => void 0,
    profile: this.modoDesenvolvimento ? console.profile : (..._args: any[]) => void 0,
    table: this.modoDesenvolvimento ? console.table : (..._args: any[]) => void 0,
    time: this.modoDesenvolvimento ? console.time : (..._args: any[]) => void 0,
    timeEnd: this.modoDesenvolvimento ? console.timeEnd : (..._args: any[]) => void 0,
    trace: this.modoDesenvolvimento ? console.trace : (..._args: any[]) => void 0,
    warn: this.modoDesenvolvimento ? console.warn : (..._args: any[]) => void 0
  };

  info(mensagem: string, autorizarEmProducao = false) {
    this.log(mensagem, Depurador.estilos.azul, autorizarEmProducao);
  }

  erro(objeto: string | unknown, autorizarEmProducao = false) {
    if (objeto instanceof Error) {
      this.log(objeto.message, Depurador.estilos.vermelho, autorizarEmProducao);
      console.log(objeto);
    } else {
      this.log(objeto as string, Depurador.estilos.vermelho, autorizarEmProducao);
    }
  }

  aviso(mensagem: string, autorizarEmProducao = false) {
    this.log(mensagem, Depurador.estilos.laranja, autorizarEmProducao);
  }

  sucesso(mensagem: string, autorizarEmProducao = false) {
    this.log(mensagem, Depurador.estilos.verde, autorizarEmProducao);
  }

  detalhes(mensagem: string, autorizarEmProducao = false) {
    this.log(mensagem, Depurador.estilos.cinza, autorizarEmProducao);
  }

  inspecionar(rotulo: string, objeto: unknown, autorizarEmProducao = false) {
    if (this.modoDesenvolvimento || autorizarEmProducao) {
      this.detalhes(rotulo, autorizarEmProducao);
      console.log(objeto);
    }
  }

  log(mensagem: string, estilo = '', autorizarEmProducao = false) {
    if (this.modoDesenvolvimento || autorizarEmProducao) {
      console.log(`%c${mensagem}`, estilo);
    }
  }
}
