import { tipoString, tipoExpressaoRegular } from '../predicados';

/**
 * Retorna o primeiro trecho correspondente ao padrao fornecido ou null se nenhum trecho é encontrado.
 * Lança um erro se os parâmetros de entrada não forem uma string e uma expressao regular.
 *
 * @param str A string de entrada
 * @param padrao O padrão a ser utilizado
 */
export function extrairValorComPadrao(str: string, padrao: RegExp): string | null {
  if (!tipoString(str)) throw new Error('A função aceita somente strings!');
  if (!tipoExpressaoRegular(padrao)) throw new Error('O padrão deve ser uma expressão regular!');
  const encontrado = padrao.exec(str);
  // Dá precedência ao primeiro grupo de captura. Se não há grupo de captura, retorna o trecho correspondente ao padrão inteiro.
  if (Array.isArray(encontrado) && encontrado.length > 0) return encontrado[1] || encontrado[0];
  return null;
}
