import { diferencaEntreDatas } from './diferencaEntreDatas';
import { validarData } from '../validacao';
import { obterLocalidadeDoUsuario } from '../localidade';
import { TIPO_DURACAO } from '../enums';

/**
 * Similar à função `fromNow()` da biblioteca Moment. Utiliza a API nativa `Intl`.
 *
 * Uso:
 * ```
 * console.log(duracaoAteAgora(new Date(), TIPO_DURACAO.SEGUNDOS, 'pt-BR'));
 * // Saída: agora
 * ```
 *
 * @param data
 * @param tipoDuracao Se o parâmetro for omitido, omitida, o valor `TIPO_DURACAO.SEGUNDOS` será utilizado.
 * @param localidade Um identificado de localidade Unicode BCP 47, como "pt-BR" ou "en-US". Se omitido, utiliza a localidade do usuário.
 */
export function duracaoAteAgora(
  data: Date,
  tipoDuracao: TIPO_DURACAO = TIPO_DURACAO.SEGUNDOS,
  localidade: string = obterLocalidadeDoUsuario()
): string {
  if (!validarData(data)) throw new Error('Data inválida!');
  const diferenca = diferencaEntreDatas(data, new Date(), tipoDuracao);
  const formatador = new Intl.RelativeTimeFormat(localidade, { style: 'long', numeric: 'auto' });
  return formatador.format(diferenca, tipoDuracao);
}
