import { tipoBooleano } from './tipoBooleano';
import { tipoString } from './tipoString';
import { tipoNumero } from './tipoNumero';
import { tipoData } from './tipoData';

export type TValor = boolean | string | number | Date;

export function tipoValor(o: unknown): o is TValor {
  return tipoBooleano(o) || tipoString(o) || tipoNumero(o) || tipoData(o);
}
