import { converterEmNumero } from './converterEmNumero';
import { valorNumerico } from '../validacao';

/**
 * Formato um número no formato local, utilizando a classe nativa `Intl`.
 *
 * Uso:
 * ```
 * console.log(formatoNumeroLocal('1000000,2345', 2, 'pt-BR'));
 * // Saída: 1.000.00,23
 * ```
 * @param valor
 * @param precisao Número de casas decimais. Se omitido, serão zero casas decimais.
 * @param localidade Identificador de localidade Unicode BCP 47, como "pt-BR" ou "en-US". Se omitido, o valor "pt-BR" é utilizado.
 */
export function formatoNumeroLocal(valor: number | string, precisao = 0, localidade = 'pt-BR'): string {
  if (!valorNumerico(valor)) throw new Error('A função aceita somente valores numéricos!');
  return new Intl.NumberFormat(localidade, {
    style: 'decimal',
    minimumFractionDigits: precisao,
    maximumFractionDigits: precisao
  }).format(converterEmNumero(valor));
}
