import { tipoNumero, tipoString } from '../predicados';
import { valorNumerico } from '../validacao';

/**
 * Converte em número uma string numérica localizada do tipo R$1,000.00 or R$ 1.000,00.
 * Se um número é fornecido, retorna o próprio número.
 *
 * Uso:
 * ```
 * console.log(converterEmNumero('RS$1.000,00'));
 * // Saída: 1000
 * ```
 * @param valor
 */
export function converterEmNumero(valor: string | number): number {
  if (tipoNumero(valor)) {
    if (valorNumerico(valor)) {
      return valor;
    }
    throw new Error('Somente valores numéricos são aceitos!');
  }
  if (!tipoString(valor) || !valorNumerico(valor.replace(/[^-\d.]/g, '')))
    throw new Error('Somente valores numéricos são aceitos!');
  if (valor.lastIndexOf('.') > 0 || valor.lastIndexOf(',') > 0) {
    const decimalSeparator = valor.lastIndexOf('.') > valor.lastIndexOf(',') ? '.' : ',';
    if (decimalSeparator === '.') {
      valor = valor.replace(/,/g, '');
    } else {
      valor = valor.replace(/\./g, '').replace(/,/, '.');
    }
  }

  // Retirando caracteres não numéricos, exceto "-" e "."
  valor = valor.replace(/[^-\d.]/g, '');
  // But the negative sign must only be placed at the beggining
  if (!/^-?[\d.]+$/.test(valor)) throw new Error('Entrada inválida!');

  return parseFloat(valor);
}
