function dias360(inicio, fim, metodo = METODO_DIAS_360.EXCEL) {
  if (!validarData(inicio) || !validarData(fim))
    throw new Error("A fun\xE7\xE3o aceita somente datas v\xE1lidas!");
  let diaInicial = inicio.getDate();
  const mesInicial = inicio.getMonth() + 1;
  const anoInicial = inicio.getFullYear();
  let diaFinal = fim.getDate();
  const mesFinal = fim.getMonth() + 1;
  const anoFinal = fim.getFullYear();
  if (metodo === METODO_DIAS_360.EU) {
    diaInicial = Math.min(diaInicial, 30);
    diaFinal = Math.min(diaFinal, 30);
  } else {
    if (metodo === METODO_DIAS_360.US_NASD && caiNoFinalDeFevereiro(inicio) && caiNoFinalDeFevereiro(fim)) {
      diaFinal = 30;
    }
    if (caiNoFinalDeFevereiro(inicio) || diaInicial === 31) {
      diaInicial = 30;
    }
    if (diaInicial === 30 && diaFinal === 31) {
      diaFinal = 30;
    }
  }
  return (anoFinal - anoInicial) * 360 + (mesFinal - mesInicial) * 30 + (diaFinal - diaInicial);
}

const validatePeriod = (start, end) => {
  if (!validarData(start) || !validarData(end))
    throw new Error("A fun\xE7\xE3o aceita somente datas v\xE1lidas!");
  if (end.valueOf() < start.valueOf())
    throw new Error("Per\xEDodo inv\xE1lido!");
};
function diasSobrepostos(inicioPrimeiro, fimPrimeiro, inicioSegundo, fimSegundo) {
  validatePeriod(inicioPrimeiro, fimPrimeiro);
  validatePeriod(inicioSegundo, fimSegundo);
  if (inicioSegundo.valueOf() > fimPrimeiro.valueOf() || inicioPrimeiro.valueOf() > fimSegundo.valueOf())
    return 0;
  const initial = Math.max(inicioPrimeiro.valueOf(), inicioSegundo.valueOf());
  const final = Math.min(fimPrimeiro.valueOf(), fimSegundo.valueOf());
  return diferencaEntreDatas(new Date(initial), new Date(final), TIPO_DURACAO.DIAS) + 1;
}

function intervaloCompetencias(inicio, fim) {
  const months = diferencaEntreDatas(inicio, fim, TIPO_DURACAO.MESES) + 1;
  return intervalo(months).map((monthsToAdd) => primeiroDiaDoMes(inicio, monthsToAdd));
}

