import { igual } from '../objetos';
import { achatar } from './achatar';

/**
 * Returns an array containing the common values for all arguments passed to the function, which may be single values and/or arrays of values.
 *
 * @param args One or more values and/or arrays of values to be intersected
 */
export function intersecao(...args: unknown[]): unknown[] {
  if (args.length === 0) return [];
  // Achata o primeiro argumento, se é um vetor, ou o converter em um vetor, caso contrário
  const primeiro = Array.isArray(args[0]) ? achatar(args[0]) : [args[0]];
  if (args.length === 1) return primeiro;
  const vetor = [];
  // Percorre todos os valores no primeiro argumento checando quais são comuns a todos os demais argumentos
  // Somente os que forem comuns são inseridos no vetor a ser retornado pela função
  for (let i = 0; i < primeiro.length; i++) {
    const a = primeiro[i];
    let comum = true;
    for (let j = 1; j < args.length; j++) {
      const arg = Array.isArray(args[j]) ? achatar(args[j] as unknown[]) : [args[j]];
      comum = comum && arg.some((b) => igual(a, b));
    }
    if (comum) vetor.push(a);
  }
  return vetor as unknown[];
}
