import { normalizar } from './normalizar';
import { semEspacos } from './semEspacos';

/**
 * Formata uma string no padrão `PascalCase`.
 * Lança um erro se o parâmetro de entrada não é uma string (pelas outras funções invocadas).
 *
 * @param str
 */
export function formatoPascalCase(str: string): string {
  return semEspacos(normalizar(str).replace(/(?:^\w|[A-Z]|\b\w)/g, (word) => word.toUpperCase()));
}
